import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Tooltip } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import BusCharts from "./BusCharts"; // chart component
import "./BusMap.css"; // optional CSS for better positioning

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [filter, setFilter] = useState("All");
  const [showCharts, setShowCharts] = useState(false);

  // Fetch buses every 2 minutes
  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch("http://127.0.0.1:8000/buses");
        const data = await response.json();
        setBuses(data.buses || []);
      } catch (err) {
        console.error("Failed to fetch bus data:", err);
      }
    };

    fetchData(); // initial fetch
    const interval = setInterval(fetchData, 120000); // 2 min
    return () => clearInterval(interval);
  }, []);

  const runningCount = buses.filter((b) => b.status === "Running").length;
  const ghostCount = buses.filter((b) => b.status === "Ghost").length;
  const anomalyCount = buses.filter((b) => b.status === "Anomaly").length;

  const filteredBuses =
    filter === "All"
      ? buses
      : buses.filter((b) =>
          filter === "Running"
            ? b.status === "Running"
            : filter === "Ghost"
            ? b.status === "Ghost"
            : b.status === "Anomaly"
        );

  return (
    <div style={{ height: "100vh", width: "100%", position: "relative" }}>
      {/* Filter & Chart buttons */}
      <div className="control-panel">
        <label>
          Show:{" "}
          <select value={filter} onChange={(e) => setFilter(e.target.value)}>
            <option value="All">All</option>
            <option value="Running">Running</option>
            <option value="Ghost">Ghost</option>
            <option value="Anomaly">Anomaly</option>
          </select>
        </label>
        <button onClick={() => setShowCharts(!showCharts)}>
          {showCharts ? "Hide Charts" : "Show Charts"}
        </button>
      </div>

      {/* Bus counts */}
      <div className="status-panel">
        🟢 Running: {runningCount} <br />
        🔴 Ghost: {ghostCount} <br />
        🟠 Anomaly: {anomalyCount}
      </div>

      {/* Charts */}
      {showCharts && <BusCharts buses={buses} />}

      {/* Map */}
      <MapContainer
        center={[40.7128, -74.006]}
        zoom={12}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
          url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          subdomains={["a", "b", "c", "d"]}
        />

        {filteredBuses.map((bus, index) => (
          <CircleMarker
            key={`${bus.feed}-${bus.id}-${index}`}
            center={[bus.lat, bus.lon]}
            radius={6}
            fillOpacity={1}
            color={
              bus.status === "Running"
                ? "green"
                : bus.status === "Ghost"
                ? "red"
                : "orange"
            }
          >
            <Tooltip>
              <div>
                <strong>Bus ID:</strong> {bus.id} <br />
                <strong>Feed:</strong> {bus.feed} <br />
                <strong>Status:</strong> {bus.status} <br />
                <strong>Speed:</strong>{" "}
                {bus.speed ? bus.speed.toFixed(1) + " mph" : "N/A"}
              </div>
            </Tooltip>
          </CircleMarker>
        ))}
      </MapContainer>
    </div>
  );
}
